int* maxSlidingWindow(int* nums, int n, int k, int* rs) {
    int* dq = malloc(n * sizeof(int));
    int* out = malloc(n * sizeof(int));
    int h = 0, t = 0, o = 0;
    for (int i = 0; i < n; i++) {
        while (h < t && nums[dq[t-1]] <= nums[i]) t--;
        dq[t++] = i;
        if (dq[h] <= i - k) h++;
        if (i >= k - 1) out[o++] = nums[dq[h]];
    }
    free(dq); *rs = o; return out;
}
